-- ══════════════════════════════════════════════════════════
-- PHASE 3 : MISE A JOUR COMPTEUR PROJETS
-- ══════════════════════════════════════════════════════════
UPDATE CA_clients c
SET projets = (
    SELECT COUNT(*) FROM CA_projets p
    WHERE p.client_code = c.code
    AND p.cree_par = 'seed_archives'
)
WHERE c.cree_par = 'seed_archives';

-- Correction : MESTIRI SAMIR a 2 projets (client_code MSS)
UPDATE CA_clients SET projets = 2 WHERE id = 'aaaa0000000000000000000000000040';
-- Correction : NOURI FRERES a 2 projets (client_code NRF)
UPDATE CA_clients SET projets = 2 WHERE id = 'aaaa0000000000000000000000000019';
-- Correction : SAFRAOUI FAYCAL a 2 projets (client_code SAF)
UPDATE CA_clients SET projets = 2 WHERE id = 'aaaa000000000000000000000000001b';

-- ══════════════════════════════════════════════════════════
-- VERIFICATION
-- ══════════════════════════════════════════════════════════
SELECT 'Clients inseres' AS info, COUNT(*) AS total FROM CA_clients WHERE cree_par = 'seed_archives'
UNION ALL
SELECT 'Projets inseres', COUNT(*) FROM CA_projets WHERE cree_par = 'seed_archives';
